#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline ll read(){
    ll x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
bool check_one(ll x)//行内合法判断
{
    return (!(x&(x>>1)));
}
bool check_two(ll x,ll y)//行间兼容判断
{
    return ((!(x&y))&&(!(x&(y>>1)))&&(!(x&(y<<1))));
}
CI MAXN=5e3+5;//2^12=4096 ≈5000
int n,k,s[MAXN],num[MAXN],cnt=0;
ll f[15][155][MAXN];
int main(void){
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	n=read(),k=read();
	//预处理
	for(int i=0;i<(1<<n);++i)//枚举可行的行
	{
	    if(check_one(i))
	    {
	        s[cnt++]=i;
	        for(int j=0;j<n;++j)
	        {
	            num[i]+=((i>>j)&1);
            }
        }
    }
    f[0][0][0]=1;
    //状态
    for(int i=1;i<=n+1;++i)
    {
        for(int j=0;j<=k;++j)
        {
            for(int a=0;a<cnt;++a)
            {
                for(int b=0;b<cnt;++b)
                {
                    int c=num[s[a]];
                    if((j>=c)&&check_two(s[a],s[b]))
                    {
                        f[i][j][a]+=f[i-1][j-c][b];
                    }
                }
            }
        }
    }
    write(f[n+1][k][0]);
	return false;
}
